using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Data;

namespace ContosoUniversity.Tests.Helpers;

public static class TestDbContextFactory
{
    public static SchoolContext Create()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;

        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PersonTests
{
    [TestMethod]
    public void FullName_ReturnsLastNameCommaFirstMidName()
    {
        // Arrange
        var student = new Student { LastName = "Smith", FirstMidName = "John" };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual("Smith, John", result);
    }

    [TestMethod]
    [DataRow("Doe", "Jane", "Doe, Jane", DisplayName = "Standard names")]
    [DataRow("O'Brien", "Conan", "O'Brien, Conan", DisplayName = "Name with apostrophe")]
    [DataRow("", "", ", ", DisplayName = "Empty names")]
    [DataRow("Lee", "A", "Lee, A", DisplayName = "Single character first name")]
    public void FullName_VariousInputs_ReturnsCorrectFormat(string lastName, string firstName, string expected)
    {
        // Arrange
        var student = new Student { LastName = lastName, FirstMidName = firstName };

        // Act & Assert
        Assert.AreEqual(expected, student.FullName);
    }

    [TestMethod]
    public void FullName_InstructorAlsoWorks()
    {
        // Arrange - Instructor also inherits from Person
        var instructor = new Instructor { LastName = "Kapoor", FirstMidName = "Candace" };

        // Act & Assert
        Assert.AreEqual("Kapoor, Candace", instructor.FullName);
    }
}

[TestClass]
public sealed class ErrorViewModelTests
{
    [TestMethod]
    public void ShowRequestId_WithRequestId_ReturnsTrue()
    {
        var model = new ErrorViewModel { RequestId = "abc123" };
        Assert.IsTrue(model.ShowRequestId);
    }

    [TestMethod]
    public void ShowRequestId_WithNullRequestId_ReturnsFalse()
    {
        var model = new ErrorViewModel { RequestId = null };
        Assert.IsFalse(model.ShowRequestId);
    }

    [TestMethod]
    public void ShowRequestId_WithEmptyRequestId_ReturnsFalse()
    {
        var model = new ErrorViewModel { RequestId = "" };
        Assert.IsFalse(model.ShowRequestId);
    }

    [TestMethod]
    public void ShowRequestId_WithWhitespaceRequestId_ReturnsTrue()
    {
        // string.IsNullOrEmpty returns false for whitespace
        var model = new ErrorViewModel { RequestId = "   " };
        Assert.IsTrue(model.ShowRequestId);
    }
}

