using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 5);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    [DataRow(10, 5, 2, DisplayName = "10 items / 5 per page = 2 pages")]
    [DataRow(11, 5, 3, DisplayName = "11 items / 5 per page = 3 pages (rounds up)")]
    [DataRow(0, 5, 0, DisplayName = "0 items / 5 per page = 0 pages")]
    [DataRow(5, 5, 1, DisplayName = "5 items / 5 per page = 1 page")]
    [DataRow(1, 5, 1, DisplayName = "1 item / 5 per page = 1 page")]
    [DataRow(6, 5, 2, DisplayName = "6 items / 5 per page = 2 pages")]
    [DataRow(100, 10, 10, DisplayName = "100 items / 10 per page = 10 pages")]
    [DataRow(1, 1, 1, DisplayName = "1 item / 1 per page = 1 page")]
    public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

        // Assert
        Assert.AreEqual(expectedTotalPages, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "alpha", "beta", "gamma" };

        // Act
        var list = new PaginatedList<string>(items, 3, 1, 10);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("alpha", list[0]);
        Assert.AreEqual("beta", list[1]);
        Assert.AreEqual("gamma", list[2]);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_ThirdPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int>(), 30, 3, 10);
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // 10 items, 5 per page = 2 pages; page 2 is the last
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        // 10 items, 5 per page = 2 pages; page 1 is not the last
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        // 3 items, 5 per page = 1 page; page 1 is the last
        var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPageOfData()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(7, result[1]);
        Assert.AreEqual(8, result[2]);
        Assert.AreEqual(9, result[3]);
        Assert.AreEqual(10, result[4]);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 15).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange - 12 items, 5 per page, page 3 should have 2 items (11, 12)
        var source = Enumerable.Range(1, 12).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 5);

        // Assert
        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(2, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(12, result[1]);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(0, result.TotalPages);
        Assert.AreEqual(0, result.Count);
    }

    [TestMethod]
    public void Create_SingleItem_ReturnsSinglePage()
    {
        // Arrange
        var source = new[] { 42 }.AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(1, result.TotalPages);
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(42, result[0]);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service;

    [TestInitialize]
    public void Setup()
    {
        _service = new NotificationService();
        // Drain the static queue to avoid interference from other tests
        while (_service.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _service?.Dispose();
    }

    [TestMethod]
    public void SendNotification_ThenReceive_ReturnsNotification()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("TestUser", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var notification = _service.ReceiveNotification();
        Assert.IsNull(notification);
    }

    [TestMethod]
    public void SendNotification_CreateWithDisplayName_GeneratesCorrectMessage()
    {
        // Arrange & Act
        _service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "Admin");
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("New Course 'Chemistry' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateWithDisplayName_GeneratesCorrectMessage()
    {
        _service.SendNotification("Course", "101", "Physics", EntityOperation.UPDATE, "Admin");
        var notification = _service.ReceiveNotification();

        Assert.AreEqual("Course 'Physics' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteWithDisplayName_GeneratesCorrectMessage()
    {
        _service.SendNotification("Student", "42", "John Doe", EntityOperation.DELETE, "Admin");
        var notification = _service.ReceiveNotification();

        Assert.AreEqual("Student 'John Doe' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
    {
        _service.SendNotification("Department", "5", EntityOperation.CREATE, "Admin");
        var notification = _service.ReceiveNotification();

        Assert.AreEqual("New Department (ID: 5) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_NullDisplayName_GeneratesIdBasedMessage()
    {
        _service.SendNotification("Instructor", "3", null, EntityOperation.UPDATE, "Admin");
        var notification = _service.ReceiveNotification();

        Assert.AreEqual("Instructor (ID: 3) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_EmptyDisplayName_GeneratesIdBasedMessage()
    {
        _service.SendNotification("Instructor", "3", "", EntityOperation.DELETE, "Admin");
        var notification = _service.ReceiveNotification();

        Assert.AreEqual("Instructor (ID: 3) has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WhitespaceDisplayName_GeneratesIdBasedMessage()
    {
        _service.SendNotification("Course", "7", "   ", EntityOperation.UPDATE, "Admin");
        var notification = _service.ReceiveNotification();

        Assert.AreEqual("Course (ID: 7) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DefaultUserName_SetsSystem()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_NullUserName_SetsSystem()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE, null);
        var notification = _service.ReceiveNotification();

        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToApproximatelyNow()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var notification = _service.ReceiveNotification();

        Assert.IsTrue(notification.CreatedAt >= before, $"CreatedAt {notification.CreatedAt} should be >= {before}");
        Assert.IsTrue(notification.CreatedAt <= after, $"CreatedAt {notification.CreatedAt} should be <= {after}");
    }

    [TestMethod]
    public void SendNotification_SetsIsReadToFalse()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
    {
        // Arrange
        _service.SendNotification("A", "1", EntityOperation.CREATE);
        _service.SendNotification("B", "2", EntityOperation.UPDATE);
        _service.SendNotification("C", "3", EntityOperation.DELETE);

        // Act & Assert - should come out in FIFO order
        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();
        var third = _service.ReceiveNotification();
        var fourth = _service.ReceiveNotification();

        Assert.AreEqual("A", first.EntityType);
        Assert.AreEqual("B", second.EntityType);
        Assert.AreEqual("C", third.EntityType);
        Assert.IsNull(fourth);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op in the in-memory implementation
        _service.MarkAsRead(42);
        _service.MarkAsRead(0);
        _service.MarkAsRead(-1);
        // If we get here without exception, the test passes
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        service.Dispose();
        // If we get here without exception, the test passes
    }

    [TestMethod]
    public void SendNotification_SetsOperationString()
    {
        _service.SendNotification("Test", "1", EntityOperation.CREATE);
        Assert.AreEqual("CREATE", _service.ReceiveNotification().Operation);

        _service.SendNotification("Test", "2", EntityOperation.UPDATE);
        Assert.AreEqual("UPDATE", _service.ReceiveNotification().Operation);

        _service.SendNotification("Test", "3", EntityOperation.DELETE);
        Assert.AreEqual("DELETE", _service.ReceiveNotification().Operation);
    }

    [TestMethod]
    public void SendNotification_FiveParamOverload_WithDisplayName()
    {
        _service.SendNotification("Department", "10", "Engineering", EntityOperation.CREATE, "Admin");
        var notification = _service.ReceiveNotification();

        Assert.AreEqual("Department", notification.EntityType);
        Assert.AreEqual("10", notification.EntityId);
        Assert.AreEqual("New Department 'Engineering' has been created", notification.Message);
        Assert.AreEqual("Admin", notification.CreatedBy);
    }
}

