namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context;
    private HomeController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
        _controller = new HomeController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void About_EmptyDatabase_ReturnsViewWithEmptyList()
    {
        var result = _controller.About() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void About_WithStudents_ReturnsGroupedData()
    {
        // Arrange
        var date1 = new DateTime(2020, 9, 1);
        var date2 = new DateTime(2021, 9, 1);
        _context.Students.Add(new Student { LastName = "A", FirstMidName = "B", EnrollmentDate = date1 });
        _context.Students.Add(new Student { LastName = "C", FirstMidName = "D", EnrollmentDate = date1 });
        _context.Students.Add(new Student { LastName = "E", FirstMidName = "F", EnrollmentDate = date2 });
        _context.SaveChanges();

        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);

        var group1 = model.Single(g => g.EnrollmentDate == date1);
        var group2 = model.Single(g => g.EnrollmentDate == date2);
        Assert.AreEqual(2, group1.StudentCount);
        Assert.AreEqual(1, group2.StudentCount);
    }

    [TestMethod]
    public void About_SingleStudent_ReturnsSingleGroup()
    {
        // Arrange
        var date = new DateTime(2023, 1, 15);
        _context.Students.Add(new Student { LastName = "Solo", FirstMidName = "Han", EnrollmentDate = date });
        _context.SaveChanges();

        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual(date, model[0].EnrollmentDate);
        Assert.AreEqual(1, model[0].StudentCount);
    }

    [TestMethod]
    public void Contact_ReturnsViewResult()
    {
        var result = _controller.Contact();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Contact_SetsViewBagMessage()
    {
        var result = _controller.Contact() as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Your contact page.", result.ViewData["Message"]);
    }

    [TestMethod]
    public void Error_ReturnsViewResult()
    {
        var result = _controller.Error();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Unauthorized_ReturnsViewResult()
    {
        var result = _controller.Unauthorized();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Unauthorized_SetsViewBagMessage()
    {
        var result = _controller.Unauthorized() as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("You don't have permission to access this resource.", result.ViewData["Message"]);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
