using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context;
    private StudentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
        _controller = new StudentsController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        _controller.TempData = new TempDataDictionary(
            _controller.ControllerContext.HttpContext,
            Mock.Of<ITempDataProvider>()
        );
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { LastName = "Zebra", FirstMidName = "Zoe", EnrollmentDate = new DateTime(2023, 9, 1) },
            new Student { LastName = "Apple", FirstMidName = "Anna", EnrollmentDate = new DateTime(2022, 9, 1) },
            new Student { LastName = "Mango", FirstMidName = "Mike", EnrollmentDate = new DateTime(2024, 1, 15) }
        );
        _context.SaveChanges();
    }

    // === Index Tests ===

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
        Assert.AreEqual("Apple", model[0].LastName);
        Assert.AreEqual("Mango", model[1].LastName);
        Assert.AreEqual("Zebra", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Zebra", model[0].LastName);
        Assert.AreEqual("Mango", model[1].LastName);
        Assert.AreEqual("Apple", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Apple", model[0].LastName); // 2022
        Assert.AreEqual("Zebra", model[1].LastName); // 2023
        Assert.AreEqual("Mango", model[2].LastName); // 2024
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Mango", model[0].LastName); // 2024
        Assert.AreEqual("Zebra", model[1].LastName); // 2023
        Assert.AreEqual("Apple", model[2].LastName); // 2022
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersStudents()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, "Apple", null) as ViewResult;

        // Assert
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Apple", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersStudents()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, "Zoe", null) as ViewResult;

        // Assert
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Zebra", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchNoMatch_ReturnsEmptyList()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, "NonExistent", null) as ViewResult;

        // Assert
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Index_NewSearchString_ResetsPageToOne()
