using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class DbInitializerTests
{
    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsStudents()
    {
        // Arrange
        var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(8, context.Students.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsInstructors()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        Assert.AreEqual(5, context.Instructors.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsDepartments()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        Assert.AreEqual(4, context.Departments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourses()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        Assert.AreEqual(7, context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsEnrollments()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        Assert.AreEqual(11, context.Enrollments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        Assert.AreEqual(3, context.OfficeAssignments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourseAssignments()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        Assert.AreEqual(8, context.CourseAssignments.Count());
    }

    [TestMethod]
    public void Initialize_AlreadySeeded_DoesNotDuplicate()
    {
        // Arrange
        var context = TestDbContextFactory.Create();

        // Act - Initialize twice
        DbInitializer.Initialize(context);
        DbInitializer.Initialize(context);

        // Assert - counts should remain the same (idempotent)
        Assert.AreEqual(8, context.Students.Count());
        Assert.AreEqual(5, context.Instructors.Count());
        Assert.AreEqual(4, context.Departments.Count());
        Assert.AreEqual(7, context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_SeedsSpecificStudentNames()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        var studentNames = context.Students.Select(s => s.LastName).OrderBy(n => n).ToList();
        Assert.IsTrue(studentNames.Contains("Alexander"));
        Assert.IsTrue(studentNames.Contains("Alonso"));
        Assert.IsTrue(studentNames.Contains("Anand"));
        Assert.IsTrue(studentNames.Contains("Barzdukas"));
        Assert.IsTrue(studentNames.Contains("Li"));
        Assert.IsTrue(studentNames.Contains("Justice"));
        Assert.IsTrue(studentNames.Contains("Norman"));
        Assert.IsTrue(studentNames.Contains("Olivetto"));
    }

    [TestMethod]
    public void Initialize_SeedsSpecificInstructorNames()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        var instructorNames = context.Instructors.Select(i => i.LastName).OrderBy(n => n).ToList();
        Assert.IsTrue(instructorNames.Contains("Abercrombie"));
        Assert.IsTrue(instructorNames.Contains("Fakhouri"));
        Assert.IsTrue(instructorNames.Contains("Harui"));
        Assert.IsTrue(instructorNames.Contains("Kapoor"));
        Assert.IsTrue(instructorNames.Contains("Zheng"));
    }

    [TestMethod]
    public void Initialize_SeedsSpecificDepartments()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        var deptNames = context.Departments.Select(d => d.Name).OrderBy(n => n).ToList();
        Assert.IsTrue(deptNames.Contains("English"));
        Assert.IsTrue(deptNames.Contains("Mathematics"));
        Assert.IsTrue(deptNames.Contains("Engineering"));
        Assert.IsTrue(deptNames.Contains("Economics"));
    }

    [TestMethod]
    public void Initialize_SeedsSpecificCourses()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        var courseTitles = context.Courses.Select(c => c.Title).OrderBy(t => t).ToList();
        Assert.IsTrue(courseTitles.Contains("Chemistry"));
        Assert.IsTrue(courseTitles.Contains("Microeconomics"));
        Assert.IsTrue(courseTitles.Contains("Macroeconomics"));
        Assert.IsTrue(courseTitles.Contains("Calculus"));
        Assert.IsTrue(courseTitles.Contains("Trigonometry"));
        Assert.IsTrue(courseTitles.Contains("Composition"));
        Assert.IsTrue(courseTitles.Contains("Literature"));
    }

    [TestMethod]
    public void Initialize_DepartmentsHaveAdministrators()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        var departments = context.Departments.ToList();
        Assert.IsTrue(departments.All(d => d.InstructorID != null),
            "All departments should have an administrator assigned");
    }

    [TestMethod]
    public void Initialize_CoursesHaveCorrectCredits()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        var chemistry = context.Courses.Single(c => c.Title == "Chemistry");
        Assert.AreEqual(3, chemistry.Credits);

        var calculus = context.Courses.Single(c => c.Title == "Calculus");
        Assert.AreEqual(4, calculus.Credits);
    }

    [TestMethod]
    public void Initialize_EnrollmentsHaveGrades()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        // Alexander's Chemistry enrollment should have grade A
        var alexander = context.Students.Single(s => s.LastName == "Alexander");
        var chemistry = context.Courses.Single(c => c.Title == "Chemistry");
        var enrollment = context.Enrollments.Single(e => e.StudentID == alexander.ID && e.CourseID == chemistry.CourseID);
        Assert.AreEqual(Grade.A, enrollment.Grade);
    }

    [TestMethod]
    public void Initialize_SomeEnrollmentsHaveNoGrade()
    {
        var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        // Anand's Chemistry enrollment should have no grade
        var anand = context.Students.Single(s => s.LastName == "Anand");
        var chemistry = context.Courses.Single(c => c.Title == "Chemistry");
        var enrollment = context.Enrollments.Single(e => e.StudentID == anand.ID && e.CourseID == chemistry.CourseID);
        Assert.IsNull(enrollment.Grade);
    }
}

